exercises.solution_code:
#include <iostream>

int arraySum(const int* arr, int length)
{
    int total{ 0 };
    for (int i{ 0 }; i < length; ++i)
        total += arr[i];
    return total;
}

int main()
{
    int n{};
    std::cin >> n;

    int arr[10]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    std::cout << "sum: " << arraySum(arr, n) << '\n';

    return 0;
}

